## Testing
```rust
#[test]
fn test_circuit_trips_after_threshold_failures() {
    let config = CircuitBreakerConfig {
        failure_threshold: 3,
        ..Default::default()
    };
    let mut health = WorkerHealth::with_config(config);

    // First two failures: degraded but circuit closed
    health.update(HealthCheckResult::failure("err".into()));
    assert!(health.circuit.is_closed());

    health.update(HealthCheckResult::failure("err".into()));
    assert!(health.circuit.is_closed());

    // Third failure: circuit trips
    health.update(HealthCheckResult::failure("err".into()));
    assert!(health.circuit.is_open());
}

#[test]
fn test_circuit_closes_after_successful_probe() {
    let mut health = WorkerHealth::default();
    // Manually set to half-open
    health.circuit = CircuitState::HalfOpen {
        entered_at: Instant::now(),
    };

    // Successful probe
    health.update(HealthCheckResult::success(50));
    assert!(health.circuit.is_closed());
}

#[test]
fn test_circuit_retrips_after_failed_probe() {
    let mut health = WorkerHealth::default();
    // Set to half-open
    health.circuit = CircuitState::HalfOpen {
        entered_at: Instant::now(),
    };

    // Failed probe
    health.update(HealthCheckResult::failure("still down".into()));
    assert!(health.circuit.is_open());

    // Trip count should be incremented
    if let CircuitState::Open { trip_count, .. } = health.circuit {
        assert!(trip_count >= 1);
    }
}
```

