fn parse_selection_request(request: &Request) -> Result<SelectionRequest> {
    // ... existing parsing ...

    // Parse toolchain if provided
    let toolchain = query.get("toolchain")
        .map(|s| serde_json::from_str(s))
        .transpose()?;

    Ok(SelectionRequest {
        // ... existing fields ...
        toolchain,
    })
}
```

### 3. Update ExecutionRequest (Worker Protocol)
```rust
// In rch-common/src/protocol.rs or worker protocol

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct ExecutionRequest {
    pub command: String,
    pub working_dir: PathBuf,
    pub env: HashMap<String, String>,
    pub toolchain: Option<ToolchainInfo>,  // NEW
}
```

### 4. Update Transfer Pipeline
```rust
// In rch/src/transfer.rs

impl TransferPipeline {
    /// Execute command on remote worker with toolchain
    pub async fn execute_remote(
        &self,
        worker: &WorkerConfig,
        command: &str,
        toolchain: Option<&ToolchainInfo>,
    ) -> Result<ExecutionResult> {
        let wrapped_command = match toolchain {
            Some(tc) => format!(
                "rustup run {} {}",
                tc.rustup_toolchain(),
                command
            ),
            None => command.to_string(),
        };

        self.ssh_client.execute(&wrapped_command).await
    }
}
```

### 5. Update Hook to Pass Toolchain
```rust
// In rch/src/hook.rs

async fn handle_compilation(command: &str, project_root: &Path) -> HookDecision {
    // Detect toolchain
    let toolchain = detect_toolchain(project_root).ok();

    // Include in selection request
    let request = SelectionRequest {
        project_id: project_id.clone(),
        required_cores: estimate_cores(command),
        preferred_workers: vec![],
        toolchain: toolchain.clone(),
    };

    // ... query daemon ...

    // Include in execution
    let result = pipeline.execute_remote(
        &worker,
        command,
        toolchain.as_ref(),
    ).await;
}
```

## Protocol Wire Format

The toolchain can be sent as:
1. Query parameter (URL-encoded JSON)
2. Request body (for POST requests)
3. Custom header

Recommended: URL-encoded JSON in query param for GET, body for POST.

```
GET /select-worker?project=foo&cores=4&toolchain=%7B%22channel%22%3A%22nightly%22%2C%22date%22%3A%222024-01-15%22%7D
```

Or cleaner with POST body:
```json
{
  "project_id": "foo",
  "required_cores": 4,
  "toolchain": {
    "channel": "nightly",
    "date": "2024-01-15"
  }
}
```

